#!/usr/bin/env node
/**
 * feishu-timeout-guard check script
 *
 * Run on gateway startup or via cron/heartbeat to:
 * 1. Verify the Feishu bot.ts patch is still intact
 * 2. Process any pending followup entries (nudge sessions that timed out)
 * 3. Report status
 *
 * Usage: node check.mjs [--verify-only] [--process-queue] [--quiet]
 */

import { readFileSync, existsSync } from "fs";
import { join } from "path";

const HOME = process.env.HOME || "/tmp";
const GUARD_DIR = join(HOME, ".openclaw/extensions/feishu-timeout-guard");
const QUEUE_FILE = join(GUARD_DIR, "pending-followups.jsonl");
const BOT_TS = join(HOME, ".local/lib/node_modules/openclaw/extensions/feishu/src/bot.ts");

const PATCH_MARKERS = ["needsFollowupDelivery", "35000", "这轮处理有点慢", "enqueuePendingFollowup"];

function verifyPatch() {
  if (!existsSync(BOT_TS)) {
    console.error("❌ bot.ts not found at", BOT_TS);
    return false;
  }
  const content = readFileSync(BOT_TS, "utf-8");
  const missing = PATCH_MARKERS.filter((m) => !content.includes(m));
  if (missing.length > 0) {
    console.error("❌ Patch NOT intact. Missing markers:", missing.join(", "));
    console.error("   The Feishu plugin may have been updated and overwritten the patch.");
    console.error("   Re-apply the patch or run the auto-patcher.");
    return false;
  }
  console.log("✅ Patch intact. All markers present in bot.ts");
  return true;
}

function checkQueue() {
  if (!existsSync(QUEUE_FILE)) {
    console.log("📭 No pending followups.");
    return [];
  }
  const lines = readFileSync(QUEUE_FILE, "utf-8").trim().split("\n").filter(Boolean);
  if (lines.length === 0) {
    console.log("📭 No pending followups.");
    return [];
  }
  const entries = lines.map((l) => {
    try { return JSON.parse(l); } catch { return null; }
  }).filter(Boolean);
  console.log(`📬 ${entries.length} pending followup(s):`);
  for (const e of entries) {
    const age = Math.round((Date.now() - e.timestamp) / 1000);
    console.log(`   - session=${e.sessionKey} chat=${e.chatId} reason=${e.reason} age=${age}s`);
  }
  return entries;
}

// Main
