      let needsFollowupDelivery = false;
      const slowNoticeTimer = setTimeout(() => {
        try {
          dispatcher.sendFinalReply({
            text: "这轮处理有点慢，我继续跑，稍后给你结果。",
          });
          sentSlowNotice = true;
          needsFollowupDelivery = true;
          log(\`feishu[\${account.accountId}]: sent slow-processing notice (session=\${route.sessionKey})\`);
        } catch (slowNoticeErr) {
          error(
            \`feishu[\${account.accountId}]: failed to send slow-processing notice: \${String(slowNoticeErr)}\`,
          );
        }
      }, 35000);
      slowNoticeTimer.unref?.();`;

const TIMEOUT_FALLBACK_BLOCK = `      if (!queuedFinal) {
        try {
          dispatcher.sendFinalReply({
            text: "这轮执行超时了，我继续处理中，稍后补给你。",
          });
          needsFollowupDelivery = true;
          log(\`feishu[\${account.accountId}]: sent timeout fallback reply (session=\${route.sessionKey})\`);
        } catch (fallbackErr) {
          error(
            \`feishu[\${account.accountId}]: failed to send timeout fallback reply: \${String(fallbackErr)}\`,
          );
        }
      }

      if (needsFollowupDelivery) {
        try {
          enqueuePendingFollowup({
            sessionKey: route.sessionKey,
            chatId: ctx.chatId,
            accountId: account.accountId,
            timestamp: Date.now(),
            reason: queuedFinal ? "slow_notice" : "timeout_fallback",
          });
          log(\`feishu[\${account.accountId}]: enqueued pending followup (session=\${route.sessionKey}, reason=\${queuedFinal ? "slow_notice" : "timeout_fallback"})\`);
        } catch (enqueueErr) {
          error(
            \`feishu[\${account.accountId}]: failed to enqueue pending followup: \${String(enqueueErr)}\`,
          );
        }
      }`;

const MARKERS = ["needsFollowupDelivery", "35000", "这轮处理有点慢", "enqueuePendingFollowup"];

const args = process.argv.slice(2);
const dryRun = args.includes("--dry-run");
const force = args.includes("--force");

if (!existsSync(BOT_TS)) {
  console.error("❌ bot.ts not found:", BOT_TS);
  process.exit(1);
}

const content = readFileSync(BOT_TS, "utf-8");
const missing = MARKERS.filter((m) => !content.includes(m));

if (missing.length === 0 && !force) {
  console.log("✅ Patch already intact. Nothing to do.");
  process.exit(0);
}

console.log("⚠️  Patch missing markers:", missing.join(", "));
console.log(force ? "   --force: re-applying anyway." : "   Applying patch...");

if (dryRun) {
  console.log("   --dry-run: would patch but not writing.");
  process.exit(0);
}

// Backup
const backupPath = BOT_TS + BACKUP_SUFFIX;
if (!existsSync(backupPath)) {
  copyFileSync(BOT_TS, backupPath);
  console.log("   Backup saved:", backupPath);
}

// Check if import already exists
let patched = content;
if (!patched.includes("enqueuePendingFollowup")) {
  // Add import after first import line
  const firstImportEnd = patched.indexOf("\n") + 1;
  patched = patched.slice(0, firstImportEnd) + IMPORT_LINE + "\n" + patched.slice(firstImportEnd);
  console.log("   Added import for enqueuePendingFollowup");
}

// Check if slow notice timer already exists
if (!patched.includes("needsFollowupDelivery")) {
  // Find the dispatch anchor and inject after it
  const anchorIdx = patched.indexOf(PATCH_ANCHOR);
  if (anchorIdx === -1) {
    console.error("❌ Could not find dispatch anchor in bot.ts. Manual patch required.");
    process.exit(1);
  }
  const insertPoint = patched.indexOf("\n", anchorIdx) + 1;
  patched = patched.slice(0, insertPoint) + PATCH_BLOCK + "\n" + patched.slice(insertPoint);
  console.log("   Injected slow-notice timer block");
}

// Check if timeout fallback + enqueue exists
if (!patched.includes("enqueued pending followup")) {
  // Find "if (isGroup && historyKey && chatHistories)" after dispatch complete
  const historyAnchor = "if (isGroup && historyKey && chatHistories)";
  // Find the one that comes after "dispatch complete"
  const dispatchCompleteIdx = patched.indexOf("dispatch complete (queuedFinal=");
  if (dispatchCompleteIdx > 0) {
    const historyIdx = patched.lastIndexOf(historyAnchor, dispatchCompleteIdx);
    if (historyIdx > 0) {
      patched = patched.slice(0, historyIdx) + TIMEOUT_FALLBACK_BLOCK + "\n\n      " + patched.slice(historyIdx);
      console.log("   Injected timeout fallback + enqueue block");
    }
  }
}

writeFileSync(BOT_TS, patched, "utf-8");

// Verify
const verify = readFileSync(BOT_TS, "utf-8");
const stillMissing = MARKERS.filter((m) => !verify.includes(m));
if (stillMissing.length === 0) {
  console.log("✅ Patch applied successfully.");
} else {
  console.error("⚠️  Patch partially applied. Still missing:", stillMissing.join(", "));
  console.error("   Manual review recommended.");
  process.exit(1);
}

