 * feishu-timeout-guard
 *
 * Lightweight OpenClaw extension that:
 * 1. Watches a pending-followup queue file written by the patched Feishu bot.ts
 * 2. On gateway startup or periodic check, re-dispatches a nudge to sessions
 *    that timed out without a final reply.
 * 3. Provides a patch-verify command to check if the bot.ts patch is still intact.
 *
 * Queue file: ~/.openclaw/extensions/feishu-timeout-guard/pending-followups.jsonl
 * Each line: { sessionKey, chatId, accountId, timestamp, reason }
 */

import { readFileSync, writeFileSync, appendFileSync, existsSync, mkdirSync } from "fs";
import { join, dirname } from "path";

const QUEUE_DIR = join(
  process.env.HOME || "/tmp",
  ".openclaw/extensions/feishu-timeout-guard",
);
const QUEUE_FILE = join(QUEUE_DIR, "pending-followups.jsonl");
const PATCH_MARKERS = ["needsFollowupDelivery", "35000", "这轮处理有点慢"];

export interface PendingFollowup {
  sessionKey: string;
  chatId: string;
  accountId: string;
  timestamp: number;
  reason: "slow_notice" | "timeout_fallback";
}

/** Append a pending followup entry (called from patched bot.ts) */
export function enqueuePendingFollowup(entry: PendingFollowup): void {
  try {
    if (!existsSync(QUEUE_DIR)) mkdirSync(QUEUE_DIR, { recursive: true });
    appendFileSync(QUEUE_FILE, JSON.stringify(entry) + "\n", "utf-8");
  } catch {
    // Best-effort; don't crash the main dispatch path
  }
}

/** Read all pending followups */
export function readPendingFollowups(): PendingFollowup[] {
  if (!existsSync(QUEUE_FILE)) return [];
  try {
    const lines = readFileSync(QUEUE_FILE, "utf-8").trim().split("\n").filter(Boolean);
    return lines.map((l) => JSON.parse(l));
  } catch {
    return [];
  }
}

/** Clear the queue after processing */
export function clearPendingFollowups(): void {
  try {
    writeFileSync(QUEUE_FILE, "", "utf-8");
  } catch {
    // Best-effort
  }
}

/** Remove a specific entry by sessionKey */
export function removePendingFollowup(sessionKey: string): void {
  const entries = readPendingFollowups().filter((e) => e.sessionKey !== sessionKey);
  try {
    writeFileSync(QUEUE_FILE, entries.map((e) => JSON.stringify(e)).join("\n") + (entries.length ? "\n" : ""), "utf-8");
  } catch {
    // Best-effort
  }
}

/** Verify that the Feishu bot.ts patch is still intact */
export function verifyPatchIntact(botTsPath?: string): {
  intact: boolean;
  missing: string[];
} {
  const path =
    botTsPath ||
    join(
      process.env.HOME || "/tmp",
      ".local/lib/node_modules/openclaw/extensions/feishu/src/bot.ts",
    );
  if (!existsSync(path)) return { intact: false, missing: ["file_not_found"] };
  try {
    const content = readFileSync(path, "utf-8");
    const missing = PATCH_MARKERS.filter((m) => !content.includes(m));
    return { intact: missing.length === 0, missing };
  } catch {
    return { intact: false, missing: ["read_error"] };
  }
}
